exercises.snippet:
subscribers = {}
def subscribe(t, h):
    subscribers.setdefault(t, []).append(h)
def publish(t, p):
    for h in subscribers.get(t, []):
        h(p)
subscribe('e', lambda p: print('A', p))
subscribe('e', lambda p: print('B', p))
publish('e', 7)

